     * @param pollNm the pollNm to set
     */
    public void setPollNm(String pollNm) {
        this.pollNm = pollNm;
    }

    /**
     * pollIemId 리턴

 * @version 1.0
 * @see <pre>
 * &lt;&lt; 개정이력(Modification Information) &gt;&gt;
 *
 *   수정일      수정자           수정내용
 *  -------    --------    ---------------------------
 *   2009.07.03  장동한          최초 생성
 *
