 */
public class OnlinePollManage implements Serializable {

	private static final long serialVersionUID = -2949206969185434664L;

	/** 온라인POLL 아이디  */
    private String pollId;

    /** 온라인POLL 이름 */
    @EgovNullCheck
    @Size(max=255)
    private String pollNm;

    /** 온라인POLL 시작일자 */
    @EgovNullCheck
    @Pattern(regexp="^\\d{4}-\\d{2}-\\d{2}$", message="{validation.pattern.date}")
    private String pollBeginDe;

    /** 온라인POLL 종료일자 */
    @EgovNullCheck
    @Pattern(regexp="^\\d{4}-\\d{2}-\\d{2}$", message="{validation.pattern.date}")
    private String pollEndDe;

    /** 온라인POLL 종류 */
    @EgovNullCheck
    private String pollKindCode;

    /** 온라인POLL 페기유무 */
    @EgovNullCheck
    private String pollDsuseYn;

    /** 온라인POLL 자동페기 */
    @EgovNullCheck
    private String pollAutoDsuseYn;

    /** 최초등록시점 */
    private String frstRegisterPnttm;

    /** 최초등록아이디 */
    private String frstRegisterId;

    /** 최종수정일 */
    private String lastUpdusrPnttm;

    /** 최종수정자 아이디 */
    private String lastUpdusrId;

    /** 컨트롤 명령어 */
    private String cmd;

    /**
     * pollId 리턴
     *
     * @return the pollId
     */
    public String getPollId() {
        return pollId;
    }

    /**
     * pollId 설정
     *
     * @param pollId the pollId to set
     */
    public void setPollId(String pollId) {
        this.pollId = pollId;
    }

    /**
     * pollNm 리턴
     *

	 * 온라인POLL항목을 삭제한다.
	 * 
	 * @param searchVO
	 * @param commandMap
	 * @param olinePollItem
	 * @param bindingResult
	 * @param model
	 * @return "/uss/olp/opm/EgovOnlinePollRegist"
	 * @throws Exception
	 */
	@RequestMapping(value = "/uss/olp/opm/delOnlinePollItem.do")
	public String egovOnlinePollItemDelete(@ModelAttribute("searchVO") ComDefaultVO searchVO,
			@RequestParam Map<?, ?> commandMap, OnlinePollItem onlinePollItem, BindingResult bindingResult,
			RedirectAttributes redirectAttributes,
			ModelMap model) throws Exception {

		// 0. Spring Security 사용자권한 처리
		Boolean isAuthenticated = EgovUserDetailsHelper.isAuthenticated();
		if (!isAuthenticated) {
			redirectAttributes.addAttribute("message", egovMessageSource.getMessage("fail.common.login"));
			return "redirect:/uat/uia/egovLoginUsr.do";
		}

		egovOnlinePollManageService.deleteOnlinePollItem(onlinePollItem);

		return "forward:/uss/olp/opm/listOnlinePollItem.do";
	}

}

